import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"曹颖甫","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/12-曹颖甫.md","filePath":"tcm-data/05-近现代/12-曹颖甫.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/12-曹颖甫.md"};function n(i,t,s,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="曹颖甫" tabindex="-1">曹颖甫 <a class="header-anchor" href="#曹颖甫" aria-label="Permalink to &quot;曹颖甫&quot;">​</a></h1><blockquote><p>曹颖甫（1866-1938年），江苏江阴人 近代经方大家，&quot;经方实验&quot;的倡导者 代表作：《经方实验录》《伤寒发微》《金匮发微》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名家达，字颖甫，号拙巢</li><li><strong>生平</strong>：前清举人，后弃儒从医，1937年抗战爆发后因拒为日本人治病而被杀害</li><li><strong>经历</strong>：上海中医专门学校教授，与章太炎等交游</li><li><strong>学术地位</strong>：<strong>近代经方实验的旗手</strong>，&quot;经方实验录&quot;开创中医医案新范式</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-经方实验——医案的价值" tabindex="-1">1. 经方实验——医案的价值 <a class="header-anchor" href="#_1-经方实验——医案的价值" aria-label="Permalink to &quot;1. 经方实验——医案的价值&quot;">​</a></h3><p>曹颖甫最重要的贡献是**《经方实验录》**——这是一部真正的&quot;经方临床实录&quot;，记录了100多个经方治验的完整过程：</p><blockquote><p><strong>「经方之效，效如桴鼓。然不经过实验，谁能信之？」</strong></p></blockquote><h3 id="_2-用经方、不拘经" tabindex="-1">2. 用经方、不拘经 <a class="header-anchor" href="#_2-用经方、不拘经" aria-label="Permalink to &quot;2. 用经方、不拘经&quot;">​</a></h3><p>曹颖甫严格使用经方，但不拘泥于原方：</p><blockquote><p><strong>「用经方者，用其法，不用其方。」</strong></p></blockquote><p>他会根据病情灵活调整剂量和药味。</p><h3 id="_3-经方剂量研究" tabindex="-1">3. 经方剂量研究 <a class="header-anchor" href="#_3-经方剂量研究" aria-label="Permalink to &quot;3. 经方剂量研究&quot;">​</a></h3><p>曹颖甫非常重视经方的<strong>剂量</strong>，他考证汉代一两≈现代15.6g（后世通常用3g折算，他主张还原原剂量）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">伤寒论原量</th><th style="text-align:left;">曹颖甫常用量</th><th style="text-align:left;">后世通常用量</th></tr></thead><tbody><tr><td style="text-align:left;">桂枝</td><td style="text-align:left;">三两≈47g</td><td style="text-align:left;">15-30g</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;">麻黄</td><td style="text-align:left;">三两≈47g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;">3-9g</td></tr><tr><td style="text-align:left;">附子</td><td style="text-align:left;">一枚≈20-30g</td><td style="text-align:left;">15-30g</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;">大黄</td><td style="text-align:left;">四两≈62g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;">3-9g</td></tr></tbody></table><hr><h2 id="三、代表医案选" tabindex="-1">三、代表医案选 <a class="header-anchor" href="#三、代表医案选" aria-label="Permalink to &quot;三、代表医案选&quot;">​</a></h2><h3 id="曹颖甫《经方实验录》经典案例" tabindex="-1">曹颖甫《经方实验录》经典案例 <a class="header-anchor" href="#曹颖甫《经方实验录》经典案例" aria-label="Permalink to &quot;曹颖甫《经方实验录》经典案例&quot;">​</a></h3><p><strong>1. 桂枝汤治自汗</strong></p><blockquote><p>「某商人，自汗恶风，脉浮缓，与桂枝汤一剂而愈。彼云：『前医用黄芪、白术、防风，累月不效。』予曰：『此表虚，非表固也。不啻开门揖盗。』」</p></blockquote><p><strong>2. 麻黄汤治伤寒</strong></p><blockquote><p>「一人畏寒发热，无汗身痛，脉浮紧。与麻黄汤一剂，温覆取汗，一汗而解。此所谓『一剂知、二剂已』也。」</p></blockquote><p><strong>3. 四逆汤治少阴病</strong></p><blockquote><p>「一老妪，神疲欲寐，脉微细，四肢厥冷。予四逆汤一剂，手足即温；再剂而神清。」</p></blockquote><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「经方之效，效如桴鼓。」</strong></p></blockquote><blockquote><p><strong>「用经方者，用其法，不用其方。」</strong></p></blockquote><blockquote><p><strong>「经方不传之秘，在于剂量。」</strong></p></blockquote><blockquote><p><strong>「学医当从经方入手，则左右逢源。」</strong></p></blockquote><blockquote><p><strong>「经方者，医之规矩也。规矩既立，方圆可成。」</strong></p></blockquote><blockquote><p><strong>「治病如对敌，药量如火药。量不足则不济，量太过则自伤。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>《经方实验录》是学习经方临床的必读书</li><li>曹颖甫的&quot;经方剂量&quot;研究直接影响了李可的大剂量用药思路</li><li>推动了经方的现代临床应用</li></ul><h3 id="曹颖甫与不同类型患者处方" tabindex="-1">曹颖甫与不同类型患者处方 <a class="header-anchor" href="#曹颖甫与不同类型患者处方" aria-label="Permalink to &quot;曹颖甫与不同类型患者处方&quot;">​</a></h3><p>**患者处方（温潜黄芽天魂汤）**中：</p><ul><li>附子9g → 曹颖甫认为可增至15-30g，但初治宜缓，9g稳妥</li><li>桂枝9g → 曹颖甫常用15g，但患者（男）有上热，减量</li></ul><p>**患者处方（加减黄芽地魄汤）**中：</p><ul><li>药物剂量都在常规范围，与曹颖甫的&quot;还原剂量&quot;不同——因患者（女）有虚火，不宜大剂温药</li></ul><hr><p><em>本条目为精简框架版。曹颖甫《经方实验录》可独立扩展为《经方医案选读》专题。</em></p>',44)])])}const p=e(r,[["render",n]]);export{c as __pageData,p as default};
